<script data-cfasync="false" type="text/javascript">
// Expense management behavior: create, update, filter, bulk actions, details, export, print, and pagination.
(function(){
var expenses=<?php echo json_encode($expenses); ?>,filtered=expenses.slice(),currentPage=1,nextNo=100;function byId(id){return document.getElementById(id)}function money(v){return '₦'+Number(v||0).toLocaleString()}function statusClass(s){return s.toLowerCase()}function showNotice(t,m){var n=byId('expenseNotice');n.className='notice is-visible '+t;n.querySelector('span').textContent=m;window.scrollTo({top:n.offsetTop-20,behavior:'smooth'})}function selectedIds(){return Array.prototype.map.call(document.querySelectorAll('.row-check:checked'),function(b){return b.value})}function selectedRows(){var ids=selectedIds();return expenses.filter(function(e){return ids.indexOf(e.id)!==-1})}function csvEscape(v){return '"'+String(v).replace(/"/g,'""')+'"'}function rowsForExport(rows){return [['Date','Expense ID','Title','Category','Vendor','Amount','Payment Method','Status']].concat(rows.map(function(e){return[e.date,e.id,e.title,e.category,e.vendor,e.amount,e.method,e.status]}))}function downloadCsv(rows,name){var csv=rowsForExport(rows).map(function(r){return r.map(csvEscape).join(',')}).join('\n'),a=document.createElement('a');a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv;charset=utf-8;'}));a.download=name;document.body.appendChild(a);a.click();document.body.removeChild(a);URL.revokeObjectURL(a.href)}function data(){var cat=byId('categoryInput').value==='Other'?byId('customCategoryInput').value.trim():byId('categoryInput').value;return{id:byId('editingId').value||('EXP'+String(nextNo++).padStart(3,'0')),date:byId('dateInput').value,title:byId('titleInput').value.trim(),category:cat,vendor:byId('vendorInput').value.trim(),amount:Number(byId('amountInput').value),method:byId('methodInput').value,status:byId('statusInput').value,invoice:byId('invoiceInput').value.trim(),description:byId('descriptionInput').value.trim(),attachment:byId('attachmentInput').files[0]?byId('attachmentInput').files[0].name:'No attachment'}}function valid(e){if(!e.title||!e.category||!e.method||!e.date){showNotice('error','Please complete title, category, method, and date.');return false}if(!e.amount||e.amount<=0){showNotice('error','Expense amount must be positive.');return false}return true}function resetForm(){byId('expenseForm').reset();byId('editingId').value='';byId('dateInput').value='<?php echo expValue($today); ?>';byId('fileName').textContent='PDF, JPG, PNG accepted';byId('saveBtn').style.display='inline-flex';byId('updateBtn').style.display='none';byId('customCategoryWrap').style.display='none'}function updateStats(){var vals=filtered.map(function(e){return Number(e.amount)});byId('recordCount').textContent=expenses.length+' Expenses';byId('highestExpense').textContent=money(vals.length?Math.max.apply(Math,vals):0);byId('lowestExpense').textContent=money(vals.length?Math.min.apply(Math,vals):0)}function render(){var size=parseInt(byId('pageSize').value,10),pages=Math.max(1,Math.ceil(filtered.length/size));if(currentPage>pages)currentPage=pages;var start=(currentPage-1)*size,rows=filtered.slice(start,start+size);byId('expenseBody').innerHTML=rows.map(function(e){return'<tr><td><input type="checkbox" class="row-check" value="'+e.id+'"></td><td>'+e.date+'</td><td>'+e.id+'</td><td>'+e.title+'</td><td>'+e.category+'</td><td>'+e.vendor+'</td><td>'+money(e.amount)+'</td><td>'+e.method+'</td><td><span class="status-badge status-'+statusClass(e.status)+'"><i class="fa-solid fa-circle"></i>'+e.status+'</span></td><td><div class="action-row"><button class="btn btn-sm btn-outline-primary view-row" data-id="'+e.id+'"><i class="fa-solid fa-eye"></i> View</button><button class="btn btn-sm btn-outline-success edit-row" data-id="'+e.id+'"><i class="fa-solid fa-pen"></i> Edit</button><button class="btn btn-sm btn-outline-danger delete-row" data-id="'+e.id+'"><i class="fa-solid fa-trash"></i> Delete</button><button class="btn btn-sm btn-outline-secondary print-row" data-id="'+e.id+'"><i class="fa-solid fa-print"></i> Print</button><button class="btn btn-sm btn-outline-info"><i class="fa-solid fa-download"></i> Attachment</button></div></td></tr>'}).join('')||'<tr><td colspan="10" class="text-center text-muted fw-bold py-4">No expense records found.</td></tr>';byId('recordInfo').textContent='Showing '+(filtered.length?start+1:0)+' - '+Math.min(start+size,filtered.length)+' of '+filtered.length+' records';byId('pagination').innerHTML='<button class="page-btn" data-page="'+Math.max(1,currentPage-1)+'">Previous</button>'+Array.from({length:pages},function(_,i){return'<button class="page-btn '+(currentPage===i+1?'active':'')+'" data-page="'+(i+1)+'">'+(i+1)+'</button>'}).join('')+'<button class="page-btn" data-page="'+Math.min(pages,currentPage+1)+'">Next</button>';byId('selectAll').checked=false;updateStats()}function apply(){var from=byId('fromDate').value,to=byId('toDate').value,cat=byId('filterCategory').value,method=byId('filterMethod').value,status=byId('filterStatus').value,vendor=byId('vendorFilter').value.toLowerCase().trim(),title=byId('titleFilter').value.toLowerCase().trim();filtered=expenses.filter(function(e){return(!from||e.date>=from)&&(!to||e.date<=to)&&(!cat||e.category===cat)&&(!method||e.method===method)&&(!status||e.status===status)&&(!vendor||e.vendor.toLowerCase().indexOf(vendor)!==-1)&&(!title||e.title.toLowerCase().indexOf(title)!==-1)});currentPage=1;render()}function show(e){byId('expenseDetailsBody').innerHTML='<div class="row g-3"><div class="col-md-6"><strong>Expense ID</strong><p>'+e.id+'</p></div><div class="col-md-6"><strong>Expense Title</strong><p>'+e.title+'</p></div><div class="col-md-6"><strong>Category</strong><p>'+e.category+'</p></div><div class="col-md-6"><strong>Amount</strong><p>'+money(e.amount)+'</p></div><div class="col-md-6"><strong>Vendor</strong><p>'+e.vendor+'</p></div><div class="col-md-6"><strong>Payment Method</strong><p>'+e.method+'</p></div><div class="col-md-6"><strong>Expense Date</strong><p>'+e.date+'</p></div><div class="col-md-6"><strong>Status</strong><p>'+e.status+'</p></div><div class="col-md-6"><strong>Invoice Number</strong><p>'+e.invoice+'</p></div><div class="col-md-6"><strong>Attachment</strong><p><i class="fa-solid fa-paperclip me-2"></i>'+e.attachment+'</p><button class="btn btn-sm btn-outline-success">View</button> <button class="btn btn-sm btn-outline-primary">Download</button></div><div class="col-12"><strong>Description</strong><p>'+e.description+'</p></div></div>';new bootstrap.Modal(document.getElementById('expenseModal')).show()}function printRows(rows){var body=rowsForExport(rows).slice(1).map(function(r){return'<tr>'+r.map(function(c){return'<td>'+c+'</td>'}).join('')+'</tr>'}).join(''),w=window.open('','_blank');w.document.write('<html><head><title>Expense Report</title><style>@page{size:A4 landscape;margin:12mm}body{font-family:Arial,sans-serif}table{width:100%;border-collapse:collapse;font-size:11px}td,th{border:1px solid #777;padding:6px;text-align:left}th{background:#0f766e;color:#fff}</style></head><body><h2>Expense Management Report</h2><table><thead><tr><th>Date</th><th>Expense ID</th><th>Title</th><th>Category</th><th>Vendor</th><th>Amount</th><th>Payment Method</th><th>Status</th></tr></thead><tbody>'+body+'</tbody></table></body></html>');w.document.close();w.focus();w.print()}document.addEventListener('DOMContentLoaded',render);byId('categoryInput').addEventListener('change',function(){byId('customCategoryWrap').style.display=this.value==='Other'?'block':'none'});byId('attachmentInput').addEventListener('change',function(){byId('fileName').textContent=this.files[0]?this.files[0].name:'PDF, JPG, PNG accepted'});byId('saveBtn').addEventListener('click',function(){var e=data();if(!valid(e))return;expenses.unshift(e);filtered=expenses.slice();render();resetForm();showNotice('success','Expense saved successfully.')});byId('updateBtn').addEventListener('click',function(){var e=data(),i=expenses.findIndex(function(x){return x.id===e.id});if(!valid(e))return;if(i>=0)expenses[i]=e;filtered=expenses.slice();render();resetForm();showNotice('success','Expense updated successfully.')});byId('cancelBtn').addEventListener('click',resetForm);byId('searchBtn').addEventListener('click',apply);byId('resetFilters').addEventListener('click',function(){['fromDate','toDate','filterCategory','filterMethod','filterStatus','vendorFilter','titleFilter'].forEach(function(id){byId(id).value=''});filtered=expenses.slice();render()});byId('pageSize').addEventListener('change',function(){currentPage=1;render()});byId('pagination').addEventListener('click',function(e){if(e.target.classList.contains('page-btn')){currentPage=parseInt(e.target.dataset.page,10);render()}});byId('selectAll').addEventListener('change',function(){document.querySelectorAll('.row-check').forEach(function(b){b.checked=byId('selectAll').checked})});document.addEventListener('click',function(ev){var b=ev.target.closest('button[data-id]');if(!b)return;var id=b.dataset.id,e=expenses.find(function(x){return x.id===id});if(!e)return;if(b.classList.contains('view-row'))show(e);if(b.classList.contains('edit-row')){byId('editingId').value=e.id;byId('titleInput').value=e.title;byId('categoryInput').value=e.category;byId('amountInput').value=e.amount;byId('methodInput').value=e.method;byId('dateInput').value=e.date;byId('statusInput').value=e.status;byId('vendorInput').value=e.vendor;byId('invoiceInput').value=e.invoice;byId('descriptionInput').value=e.description;byId('saveBtn').style.display='none';byId('updateBtn').style.display='inline-flex';window.scrollTo({top:byId('expenseForm').offsetTop-20,behavior:'smooth'})}if(b.classList.contains('delete-row')&&confirm('Delete this expense record?')){expenses=expenses.filter(function(x){return x.id!==id});apply()}if(b.classList.contains('print-row'))printRows([e])});byId('deleteSelected').addEventListener('click',function(){var ids=selectedIds();if(ids.length&&confirm('Delete selected expenses?')){expenses=expenses.filter(function(e){return ids.indexOf(e.id)===-1});apply()}});byId('exportSelected').addEventListener('click',function(){downloadCsv(selectedRows(),'Selected_Expenses.csv')});byId('printSelected').addEventListener('click',function(){printRows(selectedRows())});byId('exportCsv').addEventListener('click',function(){downloadCsv(filtered,'Expense_Records.csv')});byId('exportExcel').addEventListener('click',function(){downloadCsv(filtered,'Expense_Records.xls')});byId('exportPdf').addEventListener('click',function(){printRows(filtered)});byId('printReport').addEventListener('click',function(){printRows(filtered)});
}());
</script>

